167:   // Make sure all elements in enum CSPKeyword got added to gCSPUTF16Keywords.
168:   static_assert((sizeof(gCSPUTF16Keywords) / sizeof(gCSPUTF16Keywords[0]) ==
169:                  CSP_LAST_KEYWORD_VALUE),
